mapper.select:
/* ---- 按 项目+业态+招商负责人 汇总 ---- */ SELECT lc.project_id AS projectId, COALESCE(cs.format_type, '') AS formatType, 0 AS investmentManagerId,
/* 意向指标（关联意向表） */ COUNT(DISTINCT CASE WHEN ii.status NOT IN (4,5) THEN ii.id END) AS intentionCount, COUNT(DISTINCT CASE WHEN ii.status = 2 THEN ii.id END) AS intentionSigned, COUNT(DISTINCT CASE WHEN ii.status NOT IN (4,5) AND DATE(ii.created_at) = #{statDate} THEN ii.id END) AS newIntention,
/* 合同指标 */ COUNT(DISTINCT CASE WHEN lc.status = 2 THEN lc.id END) AS contractCount, SUM(CASE WHEN lc.status = 2 THEN COALESCE(lc.total_amount, 0) ELSE 0 END) AS contractAmount, SUM(CASE WHEN lc.status = 2 THEN COALESCE(cs.area, 0) ELSE 0 END) AS contractArea, COUNT(DISTINCT CASE WHEN lc.status = 2 AND DATE(lc.created_at) = #{statDate} THEN lc.id END) AS newContract,
/* 平均租金：合同总金额/签约面积（元/㎡，简化计算） */ CASE WHEN SUM(CASE WHEN lc.status = 2 THEN COALESCE(cs.area, 0) ELSE 0 END) > 0 THEN SUM(CASE WHEN lc.status = 2 THEN COALESCE(lc.total_amount, 0) ELSE 0 END) / SUM(CASE WHEN lc.status = 2 THEN COALESCE(cs.area, 0) ELSE 0 END) ELSE 0 END AS avgRentPrice
FROM asset_db.inv_lease_contract lc LEFT JOIN asset_db.inv_lease_contract_shop cs ON cs.contract_id = lc.id AND cs.is_deleted = 0 LEFT JOIN asset_db.inv_intention ii ON ii.id = lc.intention_id AND ii.is_deleted = 0
WHERE lc.is_deleted = 0 AND lc.project_id IS NOT NULL AND lc.contract_start <= #{statDate} /* 合同已开始 */
GROUP BY lc.project_id, COALESCE(cs.format_type, '')
/* ---- 项目级汇总（全业态合计） ---- */ UNION ALL SELECT lc.project_id, '' AS formatType, 0 AS investmentManagerId, COUNT(DISTINCT CASE WHEN ii.status NOT IN (4,5) THEN ii.id END), COUNT(DISTINCT CASE WHEN ii.status = 2 THEN ii.id END), COUNT(DISTINCT CASE WHEN ii.status NOT IN (4,5) AND DATE(ii.created_at) = #{statDate} THEN ii.id END), COUNT(DISTINCT CASE WHEN lc.status = 2 THEN lc.id END), SUM(CASE WHEN lc.status = 2 THEN COALESCE(lc.total_amount, 0) ELSE 0 END), SUM(CASE WHEN lc.status = 2 THEN COALESCE(cs.area, 0) ELSE 0 END), COUNT(DISTINCT CASE WHEN lc.status = 2 AND DATE(lc.created_at) = #{statDate} THEN lc.id END), CASE WHEN SUM(CASE WHEN lc.status = 2 THEN COALESCE(cs.area, 0) ELSE 0 END) > 0 THEN SUM(CASE WHEN lc.status = 2 THEN COALESCE(lc.total_amount, 0) ELSE 0 END) / SUM(CASE WHEN lc.status = 2 THEN COALESCE(cs.area, 0) ELSE 0 END) ELSE 0 END FROM asset_db.inv_lease_contract lc LEFT JOIN asset_db.inv_lease_contract_shop cs ON cs.contract_id = lc.id AND cs.is_deleted = 0 LEFT JOIN asset_db.inv_intention ii ON ii.id = lc.intention_id AND ii.is_deleted = 0 WHERE lc.is_deleted = 0 AND lc.project_id IS NOT NULL AND lc.contract_start <= #{statDate} GROUP BY lc.project_id
